// And groups predicates with the AND operator between them.
func And(predicates ...predicate.Church) predicate.Church {
	return predicate.Church(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Church) predicate.Church {
	return predicate.Church(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Church) predicate.Church {
	return predicate.Church(sql.NotPredicates(p))
}
